CREATE PROCEDURE interpreted_while_label(input INT4) AS $$
DECLARE
	counter INT4;
BEGIN
	<<while_label>>
	WHILE input < 1000 LOOP
		input := input + 1;
		counter := counter + 1;
		IF counter >= 10 THEN
			EXIT while_label;
		END IF;
	END LOOP;
	INSERT INTO test VALUES (input);
END;
$$ LANGUAGE plpgsql;

